-- calc_customers_is_stopped
-- Field: Customers.IsStopped
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_customers_is_stopped(p_customer_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT NULLIF(current_color, '') FROM customers WHERE customer_id = p_customer_id) = 'Green' THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

